#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, B, M;
        scanf("%lld %lld %lld", &N, &B, &M);
        long long time = 0;
        while (N > 0) {
            long long problemsToSolve = (N + 1) / 2;
            time += problemsToSolve * M;
            N -= problemsToSolve;
            if (N > 0) {
                time += B;
                M *= 2;
            }
        }
        printf("%lld\n", time);
    }
    return 0;
}

