const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, B, M] = readline().split(' ').map(Number);
    let time = 0;
    let n = N;
    let m = M;
    while (n > 0) {
        const problemsToSolve = Math.floor((n + 1) / 2);
        time += problemsToSolve * m;
        n -= problemsToSolve;
        if (n > 0) {
            time += B;
            m *= 2;
        }
    }
    console.log(time);
}
